  ('pukao-d0d1b9a2-moex-00196', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '下列何種情況可以不必列入期後事項之調整與揭露，儘管該事項發生在財務報表日與查核報告日 之間？', '["委託人發行公司債或辦理現金增資", "因颱風淹水造成設備、存貨的損失", "受查者股票價格大跌", "纏訟已久之索賠案終於定讞"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "6a0db34df973", "answer_pdf_sha1": "702ed3418265", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00197', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '對應收帳款發函詢證有助於驗證那些帳戶餘額的聲明？①存在 ②完整 ③評價 ④表達', '["僅", "", "", "僅"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "6a0db34df973", "answer_pdf_sha1": "702ed3418265", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": ["incomplete_options"], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00198', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '依審計準則210號（原審計準則公報第六十四號）「查核案件條款之協議」之規定，下列何者非查 核先決條件？', '["編製財務報表所適用之財務報導架構是否可接受", "受查者管理階層已認知並瞭解以及同意其責任，包括依照適用之財務報導架構編製財務報表 （包含財務報表之允當表達），以及維持與財務報表編製有關之必要內部控制，以確保財務報表 未存有導因於舞弊或錯誤之重大不實表達", "受查者同意會計師查核範圍、程序及公費", "受查者管理階層已認知並瞭解以及同意查核人員接觸適當人員以取得必要之查核證據，且該接 觸未受限制"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "6a0db34df973", "answer_pdf_sha1": "702ed3418265", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00199', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '下列有關個別項目聲明之敘述，何者錯誤？', '["受查者於第四季新增數家設立於境外免稅天堂之鉅額交易客戶，與交易發生聲明有關", "受查者連續兩年發生重大虧損，經評估固定資產已產生減損，與資產評價聲明有關", "受查者於期末未依採購交易條件認列進貨，導致未認列相關在途存貨及應付帳款，與交易正確 性聲明有關", "查核人員抽盤帳列固定資產，與資產之存在聲明有關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "6a0db34df973", "answer_pdf_sha1": "702ed3418265", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00200', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '下列有關查核人員為就受查者訴訟與索賠之完整性取得足夠及適切之查核證據的敘述，何者錯誤？', '["查核人員為辨認可能產生重大不實表達風險之訴訟與索賠，可查詢管理階層及受查者之其他人員", "查核人員為辨認可能產生重大不實表達風險之訴訟與索賠，可複核治理單位之會議紀錄及受查 者與其外部法律顧問之往來文件", "查核人員與受查者之外部法律顧問直接溝通，可協助查核人員對受查者是否知悉可能重大之訴 訟與索賠及管理階層對所產生財務影響之估計是否合理", "查核人員就已知訴訟或索賠辨認出重大不實表達風險，與受查者之外部法律顧問直接溝通時， 為期慎重，應寄送由會計師具名之查詢函，以要求外部法律顧問與查核人員直接溝通"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "6a0db34df973", "answer_pdf_sha1": "702ed3418265", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
  ('pukao-d0d1b9a2-moex-00201', 'pukao-d0d1b9a2', 'pukao-d0d1b9a2-moex-111-6b16960c', 'sub-pukao-d0d1b9a2-04', NULL, 'single_choice', '有關重大性之敘述，下列何者錯誤？', '["受查者之股權結構及籌資方式可能會影響整體重大性之基準", "重大性之決定屬專業判斷，且該判斷受查核人員對財務報表使用者財務資訊需求之認知所影響", "查核人員所選用之基準，攸關之財務資料僅能使用當期之財務狀況、預算或預測", "查核人員應於規劃查核工作階段，決定財務報表整體重大性"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:02+00:00", "source_pdf_sha1": "6a0db34df973", "answer_pdf_sha1": "702ed3418265", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "416", "s": "1008", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "會計"}'::jsonb, NULL),
